"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["85492"],{45353(e){e.exports=JSON.parse('{"tag":{"label":"socnet","permalink":"/sysanalyst-kb.github.io/tech/tags/socnet","allTagsPath":"/sysanalyst-kb.github.io/tech/tags","count":3,"items":[{"id":"cdn","title":"CDN \u2014 \u0434\u043E\u0441\u0442\u0430\u0432\u043A\u0430 \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430","description":"CDN (Content Delivery Network) \u2014 \u0433\u0435\u043E\u0433\u0440\u0430\u0444\u0438\u0447\u0435\u0441\u043A\u0438 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u0430\u044F \u0441\u0435\u0442\u044C \u0441\u0435\u0440\u0432\u0435\u0440\u043E\u0432 (edge nodes / PoP) \u0434\u043B\u044F \u0431\u044B\u0441\u0442\u0440\u043E\u0439 \u0434\u043E\u0441\u0442\u0430\u0432\u043A\u0438 \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044F\u043C. \u041A\u044D\u0448\u0438\u0440\u0443\u0435\u0442 \u0441\u0442\u0430\u0442\u0438\u043A\u0443 (\u0432\u0438\u0434\u0435\u043E, \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F, JS/CSS) \u043D\u0430 \u0443\u0437\u043B\u0430\u0445 \u0440\u044F\u0434\u043E\u043C \u0441 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u043C. \u041E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u043F\u0440\u043E\u0432\u0430\u0439\u0434\u0435\u0440\u044B cache strategy (TTL, cache-control, purging), origin shield, multi-CDN, cost optimization (egress bandwidth) \u0438 \u043C\u0435\u0442\u0440\u0438\u043A\u0438 (hit ratio, latency, bandwidth).","permalink":"/sysanalyst-kb.github.io/tech/cdn"},{"id":"websocket","title":"WebSocket / SSE \u2014 real-time \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B\u044B","description":"WebSocket \u2014 full-duplex \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B \u043F\u043E\u0432\u0435\u0440\u0445 TCP (RFC 6455) \u0434\u043B\u044F real-time \u043A\u043E\u043C\u043C\u0443\u043D\u0438\u043A\u0430\u0446\u0438\u0439 (\u0447\u0430\u0442\u044B, \u0443\u0432\u0435\u0434\u043E\u043C\u043B\u0435\u043D\u0438\u044F, \u043A\u043E\u043B\u043B\u0430\u0431\u043E\u0440\u0430\u0446\u0438\u044F, live-\u0441\u0442\u0440\u0438\u043C\u044B). SSE (Server-Sent Events) \u2014 \u043E\u0434\u043D\u043E\u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u044B\u0439 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B \u043E\u0442 \u0441\u0435\u0440\u0432\u0435\u0440\u0430 \u043A \u043A\u043B\u0438\u0435\u043D\u0442\u0443 (\u043B\u0435\u043D\u0442\u0430, \u0442\u0438\u043A\u0435\u0440\u044B, \u0443\u0432\u0435\u0434\u043E\u043C\u043B\u0435\u043D\u0438\u044F). Long Polling \u2014 fallback \u0434\u043B\u044F \u0431\u0440\u0430\u0443\u0437\u0435\u0440\u043E\u0432 \u0431\u0435\u0437 WebSocket. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0432\u044B\u0431\u0438\u0440\u0430\u0435\u0442 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B \u043F\u043E\u0434 \u0441\u0446\u0435\u043D\u0430\u0440\u0438\u0439 Discord (WebSocket Gateway), Telegram (MTProto), Signal (WebSocket), Slack (WebSocket RTM).","permalink":"/sysanalyst-kb.github.io/tech/websocket"},{"id":"recommendation","title":"\u0420\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B (ML, collaborative filtering)","description":"\u0420\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u2014 ML-\u043C\u043E\u0434\u0435\u043B\u0438 \u0434\u043B\u044F \u043F\u043E\u0434\u0431\u043E\u0440\u0430 \u043F\u0435\u0440\u0441\u043E\u043D\u0430\u043B\u0438\u0437\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430. \u041E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u043F\u043E\u0434\u0445\u043E\u0434\u044B candidate generation (500-2000 \u043A\u0430\u043D\u0434\u0438\u0434\u0430\u0442\u043E\u0432) \u2192 feature computation \u2192 ranking model (DNN/GBDT) \u2192 business rules (diversity, freshness, well-being). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 candidate generation, \u0441\u0438\u0433\u043D\u0430\u043B\u044B \u0440\u0430\u043D\u0436\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, A/B \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u044B \u0438 \u043C\u0435\u0442\u0440\u0438\u043A\u0438 (CTR, watch time, recall, diversity).","permalink":"/sysanalyst-kb.github.io/tech/recommendation"}],"unlisted":false}}')}}]);